SELECT SUM(occupied_rooms) AS total_occupied_rooms
FROM occupancy_rates
WHERE property_id = 1 AND date = '2023-10-01';

SELECT AVG(base_price) AS average_base_price
FROM room_pricing
WHERE property_id = 1 AND date = '2023-05-01';

SELECT room_type_name, description
FROM room_types
WHERE property_id = 1;

SELECT AVG(walkup_price) AS average_walkup_price
FROM pricing_data
WHERE date = '2014-04-01';

SELECT occupied_rooms, occupancy_rate
FROM occupancy_rates
WHERE property_id = 0 AND date = '2014-04-01';

SELECT AVG(occupancy_rate) AS average_occupancy_rate
FROM occupancy_rates
WHERE property_id = 1 AND date BETWEEN '2014-04-01' AND '2014-04-30';
